import React, { useState, useRef, useEffect } from 'react';
import { useTaskStore } from '../store/useTaskStore';
import type { Priority, Task, Recurrence, TimeBlock } from '../types';
import { parseDateText, formatDateDisplay } from '../utils/dateParser';
import { DatePickerCalendar } from './DatePickerCalendar';
import './TaskDetailView.css';

interface Props {
  taskId: string;
}

const DAYS = ['Su', 'M', 'Tu', 'W', 'Th', 'F', 'Sa'];

// Subtask item with inline editing and delete
const SubtaskItem: React.FC<{
  subtask: { id: string; title: string; completed: boolean };
  taskId: string;
  toggleSubtask: (taskId: string, subtaskId: string) => void;
  updateSubtask: (taskId: string, subtaskId: string, title: string) => void;
  deleteSubtask: (taskId: string, subtaskId: string) => void;
}> = ({ subtask, taskId, toggleSubtask, updateSubtask, deleteSubtask }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(subtask.title);

  return (
    <div className="subtask-item" style={{ display: 'flex', alignItems: 'center', gap: '8px', padding: '4px 0' }}>
      <input 
        type="checkbox" 
        checked={subtask.completed} 
        onChange={() => toggleSubtask(taskId, subtask.id)} 
      />
      {isEditing ? (
        <input
          autoFocus
          value={editTitle}
          onChange={(e) => setEditTitle(e.target.value)}
          onBlur={() => {
            if (editTitle.trim() && editTitle !== subtask.title) {
              updateSubtask(taskId, subtask.id, editTitle.trim());
            } else {
              setEditTitle(subtask.title);
            }
            setIsEditing(false);
          }}
          onKeyDown={(e) => {
            if (e.key === 'Enter') { e.preventDefault(); (e.target as HTMLInputElement).blur(); }
            if (e.key === 'Escape') { setEditTitle(subtask.title); setIsEditing(false); }
          }}
          style={{ flex: 1, border: 'none', borderBottom: '2px solid var(--brand-solid)', background: 'transparent', outline: 'none', color: 'var(--text-primary)', fontSize: 'inherit', padding: '2px 4px' }}
        />
      ) : (
        <span 
          className={subtask.completed ? 'completed' : ''}
          onDoubleClick={() => { setEditTitle(subtask.title); setIsEditing(true); }}
          style={{ flex: 1, cursor: 'text' }}
        >
          {subtask.title}
        </span>
      )}
      <button
        onClick={() => deleteSubtask(taskId, subtask.id)}
        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)', fontSize: '0.7rem', padding: '2px 4px', opacity: 0.4, flexShrink: 0 }}
        title="Delete subtask"
        className="subtask-delete-btn"
      >
        ✕
      </button>
    </div>
  );
};

// Helper to format epoch ms to HH:MM string
const epochToTimeStr = (epoch: number): string => {
  const d = new Date(epoch);
  return `${String(d.getHours()).padStart(2, '0')}:${String(d.getMinutes()).padStart(2, '0')}`;
};

// Helper to format duration
const formatBlockDuration = (startTime: number, endTime: number): string => {
  const totalSec = Math.floor((endTime - startTime) / 1000);
  const h = Math.floor(totalSec / 3600);
  const m = Math.floor((totalSec % 3600) / 60);
  if (h > 0) return `${h}h ${m}m`;
  return `${m}m`;
};

// Helper: date string from epoch
const epochToDateStr = (epoch: number): string => {
  const d = new Date(epoch);
  const y = d.getFullYear();
  const m = String(d.getMonth() + 1).padStart(2, '0');
  const day = String(d.getDate()).padStart(2, '0');
  return `${y}-${m}-${day}`;
};

// TimeBlocks section component
const TimeBlocksSection: React.FC<{
  task: Task;
  taskId: string;
  addTimeBlock: (taskId: string, startTime: number, endTime: number) => void;
  updateTimeBlock: (taskId: string, blockId: string, updates: Partial<TimeBlock>) => void;
  deleteTimeBlock: (taskId: string, blockId: string) => void;
}> = ({ task, taskId, addTimeBlock, updateTimeBlock, deleteTimeBlock }) => {
  const blocks = task.timeBlocks || [];
  const [showAddForm, setShowAddForm] = useState(false);
  const [newStartTime, setNewStartTime] = useState('');
  const [newEndTime, setNewEndTime] = useState('');
  const [editingBlockId, setEditingBlockId] = useState<string | null>(null);
  const [editStart, setEditStart] = useState('');
  const [editEnd, setEditEnd] = useState('');

  // Group blocks by date
  const grouped: Record<string, TimeBlock[]> = {};
  blocks.forEach(b => {
    const dateKey = epochToDateStr(b.startTime);
    if (!grouped[dateKey]) grouped[dateKey] = [];
    grouped[dateKey].push(b);
  });

  // Sort dates descending (most recent first)
  const sortedDates = Object.keys(grouped).sort((a, b) => b.localeCompare(a));

  const handleAddBlock = () => {
    if (!newStartTime || !newEndTime) return;
    const today = new Date();
    const [sh, sm] = newStartTime.split(':').map(Number);
    const [eh, em] = newEndTime.split(':').map(Number);
    const start = new Date(today.getFullYear(), today.getMonth(), today.getDate(), sh, sm).getTime();
    const end = new Date(today.getFullYear(), today.getMonth(), today.getDate(), eh, em).getTime();
    if (end <= start) return;
    addTimeBlock(taskId, start, end);
    setNewStartTime('');
    setNewEndTime('');
    setShowAddForm(false);
  };

  const handleSaveEdit = (blockId: string) => {
    if (!editStart || !editEnd) return;
    const block = blocks.find(b => b.id === blockId);
    if (!block) return;
    const origDate = new Date(block.startTime);
    const [sh, sm] = editStart.split(':').map(Number);
    const [eh, em] = editEnd.split(':').map(Number);
    const newStart = new Date(origDate.getFullYear(), origDate.getMonth(), origDate.getDate(), sh, sm).getTime();
    const newEnd = new Date(origDate.getFullYear(), origDate.getMonth(), origDate.getDate(), eh, em).getTime();
    if (newEnd <= newStart) return;
    updateTimeBlock(taskId, blockId, { startTime: newStart, endTime: newEnd });
    setEditingBlockId(null);
  };

  const totalTracked = blocks.reduce((sum, b) => sum + (b.endTime - b.startTime), 0);

  return (
    <div className="detail-section">
      <h3 style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
        <span>⏱ Time Blocks ({blocks.length})</span>
        {totalTracked > 0 && (
          <span style={{ fontSize: '0.8rem', fontWeight: 500, color: 'var(--text-secondary)' }}>
            Total: {formatBlockDuration(0, totalTracked)}
          </span>
        )}
      </h3>

      {sortedDates.length === 0 && !showAddForm && (
        <p style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', padding: '8px 0' }}>
          タイマーを使って記録するか、手動で追加してください。
        </p>
      )}

      {sortedDates.map(dateKey => {
        const dateBlocks = grouped[dateKey].sort((a, b) => b.startTime - a.startTime);
        const dayTotal = dateBlocks.reduce((sum, b) => sum + (b.endTime - b.startTime), 0);
        const displayDate = new Date(dateKey + 'T00:00:00');
        const isToday = epochToDateStr(Date.now()) === dateKey;

        return (
          <div key={dateKey} style={{ marginBottom: '8px' }}>
            <div style={{
              display: 'flex', alignItems: 'center', justifyContent: 'space-between',
              fontSize: '0.75rem', color: 'var(--text-secondary)', padding: '4px 0',
              borderBottom: '1px solid var(--border-color)', marginBottom: '4px'
            }}>
              <span>{isToday ? '今日' : displayDate.toLocaleDateString('ja-JP', { month: 'short', day: 'numeric', weekday: 'short' })}</span>
              <span style={{ fontWeight: 600 }}>{formatBlockDuration(0, dayTotal)}</span>
            </div>

            {dateBlocks.map(block => (
              <div key={block.id} style={{
                display: 'flex', alignItems: 'center', gap: '6px', padding: '4px 0',
                fontSize: '0.8rem'
              }}>
                {editingBlockId === block.id ? (
                  <>
                    <input
                      type="time"
                      value={editStart}
                      onChange={e => setEditStart(e.target.value)}
                      style={{
                        width: '75px', padding: '2px 4px', border: '1px solid var(--brand-solid)',
                        borderRadius: '4px', background: 'var(--bg-app)', color: 'var(--text-primary)',
                        fontSize: '0.8rem'
                      }}
                    />
                    <span style={{ color: 'var(--text-secondary)' }}>–</span>
                    <input
                      type="time"
                      value={editEnd}
                      onChange={e => setEditEnd(e.target.value)}
                      style={{
                        width: '75px', padding: '2px 4px', border: '1px solid var(--brand-solid)',
                        borderRadius: '4px', background: 'var(--bg-app)', color: 'var(--text-primary)',
                        fontSize: '0.8rem'
                      }}
                    />
                    <button
                      onClick={() => handleSaveEdit(block.id)}
                      style={{
                        padding: '2px 8px', borderRadius: '4px', border: 'none',
                        background: 'var(--brand-solid)', color: 'white', cursor: 'pointer', fontSize: '0.7rem'
                      }}
                    >✓</button>
                    <button
                      onClick={() => setEditingBlockId(null)}
                      style={{
                        padding: '2px 8px', borderRadius: '4px', border: '1px solid var(--border-color)',
                        background: 'transparent', color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.7rem'
                      }}
                    >✕</button>
                  </>
                ) : (
                  <>
                    <span
                      style={{ cursor: 'pointer', fontVariantNumeric: 'tabular-nums' }}
                      onClick={() => {
                        setEditingBlockId(block.id);
                        setEditStart(epochToTimeStr(block.startTime));
                        setEditEnd(epochToTimeStr(block.endTime));
                      }}
                      title="クリックで編集"
                    >
                      {epochToTimeStr(block.startTime)} – {epochToTimeStr(block.endTime)}
                    </span>
                    <span style={{ color: 'var(--text-secondary)', fontSize: '0.75rem', marginLeft: 'auto' }}>
                      {formatBlockDuration(block.startTime, block.endTime)}
                    </span>
                    <button
                      onClick={() => {
                        if (window.confirm('このタイムブロックを削除しますか？')) {
                          deleteTimeBlock(taskId, block.id);
                        }
                      }}
                      style={{
                        background: 'none', border: 'none', cursor: 'pointer',
                        color: 'var(--text-secondary)', fontSize: '0.65rem', padding: '2px 4px',
                        opacity: 0.5, flexShrink: 0
                      }}
                      title="Delete"
                      className="subtask-delete-btn"
                    >🗑️</button>
                  </>
                )}
              </div>
            ))}
          </div>
        );
      })}

      {showAddForm ? (
        <div style={{
          display: 'flex', alignItems: 'center', gap: '6px', padding: '6px 0',
          borderTop: '1px solid var(--border-color)', marginTop: '4px'
        }}>
          <input
            type="time"
            value={newStartTime}
            onChange={e => setNewStartTime(e.target.value)}
            style={{
              width: '80px', padding: '4px 6px', border: '1px solid var(--border-color)',
              borderRadius: '4px', background: 'var(--bg-app)', color: 'var(--text-primary)',
              fontSize: '0.8rem'
            }}
          />
          <span style={{ color: 'var(--text-secondary)', fontSize: '0.8rem' }}>–</span>
          <input
            type="time"
            value={newEndTime}
            onChange={e => setNewEndTime(e.target.value)}
            style={{
              width: '80px', padding: '4px 6px', border: '1px solid var(--border-color)',
              borderRadius: '4px', background: 'var(--bg-app)', color: 'var(--text-primary)',
              fontSize: '0.8rem'
            }}
          />
          <button
            onClick={handleAddBlock}
            style={{
              padding: '4px 12px', borderRadius: '4px', border: 'none',
              background: 'var(--brand-solid)', color: 'white', cursor: 'pointer', fontSize: '0.8rem'
            }}
          >Add</button>
          <button
            onClick={() => { setShowAddForm(false); setNewStartTime(''); setNewEndTime(''); }}
            style={{
              padding: '4px 8px', borderRadius: '4px', border: '1px solid var(--border-color)',
              background: 'transparent', color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.8rem'
            }}
          >Cancel</button>
        </div>
      ) : (
        <button
          onClick={() => setShowAddForm(true)}
          style={{
            background: 'none', border: '1px dashed var(--border-color)', borderRadius: '6px',
            color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.8rem', padding: '4px 12px',
            marginTop: '4px', width: '100%', textAlign: 'center'
          }}
        >+ 手動で追加</button>
      )}
    </div>
  );
};

export const TaskDetailView: React.FC<Props> = ({ taskId }) => {
  const { 
    tasks, 
    updateTask, 
    addComment,
    updateComment,
    deleteComment,
    addSubtask, 
    toggleSubtask,
    updateSubtask,
    deleteSubtask,
    setSelectedTaskId, 
    projects, 
    tags,
    addTag,
    moveTask,
    toggleTaskCompletion,
    deleteTask,
    selectedTaskIds,
    addTimeBlock,
    updateTimeBlock,
    deleteTimeBlock
  } = useTaskStore();
  const task = tasks.find(t => t.id === taskId);

  const handleBatchUpdate = (updates: Partial<Task>) => {
    if (selectedTaskIds.includes(taskId) && selectedTaskIds.length > 1) {
      selectedTaskIds.forEach(id => updateTask(id, updates));
    } else {
      updateTask(taskId, updates);
    }
  };

  const handleBatchMove = (newProjectId: string | null) => {
    if (selectedTaskIds.includes(taskId) && selectedTaskIds.length > 1) {
      selectedTaskIds.forEach(id => moveTask(id, newProjectId));
    } else {
      moveTask(taskId, newProjectId);
    }
  };

  const [newComment, setNewComment] = useState(() => sessionStorage.getItem(`draft_comment_${taskId}`) || '');
  useEffect(() => {
    if (newComment) {
      sessionStorage.setItem(`draft_comment_${taskId}`, newComment);
    } else {
      sessionStorage.removeItem(`draft_comment_${taskId}`);
    }
  }, [newComment, taskId]);

  const [newSubtask, setNewSubtask] = useState('');

  const [showDateInput, setShowDateInput] = useState(false);
  const [dateText, setDateText] = useState('');
  const dateInputRef = useRef<HTMLDivElement>(null);

  // Tag selector state
  const [showTagDropdown, setShowTagDropdown] = useState(false);
  const [tagSearch, setTagSearch] = useState('');
  const [tagSelectedIndex, setTagSelectedIndex] = useState(0);
  const tagDropdownRef = useRef<HTMLDivElement>(null);

  // Comment editing state
  const [editingCommentId, setEditingCommentId] = useState<string | null>(null);
  const [editCommentText, setEditCommentText] = useState('');

  useEffect(() => {
    const handleClickOutsideDate = (event: MouseEvent) => {
      if (dateInputRef.current && !dateInputRef.current.contains(event.target as Node)) {
        setShowDateInput(false);
      }
      if (tagDropdownRef.current && !tagDropdownRef.current.contains(event.target as Node)) {
        setShowTagDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutsideDate);
    return () => document.removeEventListener('mousedown', handleClickOutsideDate);
  }, []);

  useEffect(() => {
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setSelectedTaskId(null);
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [setSelectedTaskId]);

  if (!task) return <div className="task-detail-panel">Task not found</div>;

  const handleUpdateDescription = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    updateTask(taskId, { description: e.target.value });
  };

  const handleAddComment = (e: React.FormEvent) => {
    e.preventDefault();
    if (newComment.trim()) {
      addComment(taskId, newComment.trim());
      setNewComment('');
    }
  };

  const handleAddSubtask = (e: React.FormEvent) => {
    e.preventDefault();
    if (newSubtask.trim()) {
      addSubtask(taskId, newSubtask.trim());
      setNewSubtask('');
    }
  };

  const handleToggleRecurrence = (freq: Recurrence['frequency'] | 'none') => {
    if (freq === 'none') {
      handleBatchUpdate({ recurrence: null });
    } else {
      const defaultRecurrence: Recurrence = { frequency: freq, interval: 1 };
      if (freq === 'monthly') {
        defaultRecurrence.dayOfMonth = new Date().getDate();
      }
      handleBatchUpdate({ recurrence: defaultRecurrence });
    }
  };

  const setSpecificRecurrence = (updates: Partial<Recurrence>) => {
    if (task.recurrence) {
        handleBatchUpdate({ recurrence: { ...task.recurrence, ...updates } });
    }
  };

  const toggleDayOfWeek = (day: number) => {
    if (!task.recurrence) return;
    const currentDays = task.recurrence.daysOfWeek || [];
    const newDays = currentDays.includes(day)
      ? currentDays.filter(d => d !== day)
      : [...currentDays, day].sort();
    setSpecificRecurrence({ daysOfWeek: newDays });
  };

  // Sort projects alphabetically, blank last
  const sortedProjects = [...projects]
    .filter(p => p.id !== 'p1')
    .sort((a, b) => a.name.localeCompare(b.name, 'ja'));

  return (
    <div className="task-detail-panel">
      <div className="detail-header">
        <button className="close-btn" onClick={() => setSelectedTaskId(null)}>✕ Close</button>
        <div style={{ display: 'flex', gap: '8px', alignItems: 'center' }}>
          <button 
            className={`complete-btn-large ${task.completed ? 'completed' : ''}`}
            onClick={() => {
              const incompleteSubtasks = task.subtasks.filter(st => !st.completed);
              if (incompleteSubtasks.length > 0) {
                if (!window.confirm(`サブタスクが${incompleteSubtasks.length}件残っていますが、完了してよいですか？`)) {
                  return;
                }
              }
              toggleTaskCompletion(taskId);
            }}
          >
            {task.completed ? '✓ Completed' : 'Mark Complete'}
          </button>
          <button
            className="delete-task-btn"
            onClick={() => {
              if (window.confirm('このタスクを削除しますか？')) {
                deleteTask(taskId);
                setSelectedTaskId(null);
              }
            }}
            style={{
              background: 'none', border: '1px solid var(--priority-high)', 
              color: 'var(--priority-high)', padding: '6px 12px', borderRadius: '6px',
              cursor: 'pointer', fontSize: '0.8rem', fontWeight: 600
            }}
          >
            🗑️ Delete
          </button>
        </div>
      </div>

      <div className="detail-body">
        <textarea 
          className="detail-title-input" 
          value={task.title} 
          onChange={(e) => { updateTask(taskId, { title: e.target.value }); e.target.style.height = 'auto'; e.target.style.height = e.target.scrollHeight + 'px'; }}
          onFocus={(e) => { e.target.style.height = 'auto'; e.target.style.height = e.target.scrollHeight + 'px'; }}
          placeholder="Task Title"
          rows={1}
        />

        <div className="detail-fields">
          <div className="field-group">
            <label>Project</label>
            <div className="field-value">
               <select 
                 value={task.projectId || ''} 
                 onChange={(e) => handleBatchMove(e.target.value || null)}
               >
                 {sortedProjects.map(p => (
                   <option key={p.id} value={p.id}>{p.name}</option>
                 ))}
                 <option value="">No Project</option>
               </select>
            </div>
          </div>

          <div className="field-group">
            <label>Tags</label>
            <div className="field-value" ref={tagDropdownRef} style={{ position: 'relative' }}>
              <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px', alignItems: 'center' }}>
                {(task.tagIds || []).map(tagId => {
                  const tag = (tags || []).find(t => t.id === tagId);
                  if (!tag) return null;
                  return (
                    <span
                      key={tag.id}
                      style={{
                        display: 'inline-flex', alignItems: 'center', gap: '4px',
                        padding: '2px 8px', borderRadius: '12px', fontSize: '0.8rem', fontWeight: 500,
                        backgroundColor: tag.color + '33', color: tag.color
                      }}
                    >
                      {tag.name}
                      <button
                        onClick={() => {
                          const newTagIds = (task.tagIds || []).filter(id => id !== tag.id);
                          handleBatchUpdate({ tagIds: newTagIds });
                        }}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'inherit', fontSize: '0.7rem', padding: '0 2px', opacity: 0.6 }}
                        title="タグを削除"
                      >✕</button>
                    </span>
                  );
                })}
                <button
                  onClick={() => { setShowTagDropdown(!showTagDropdown); setTagSearch(''); setTagSelectedIndex(0); }}
                  style={{
                    background: 'none', border: '1px dashed var(--border-color)', borderRadius: '12px',
                    color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.8rem', padding: '2px 10px'
                  }}
                >+ Add</button>
              </div>
              {showTagDropdown && (
                <div style={{
                  position: 'absolute', top: '100%', left: 0, zIndex: 20,
                  backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-color)',
                  borderRadius: '6px', padding: '4px', marginTop: '4px', minWidth: '200px',
                  boxShadow: '0 4px 12px rgba(0,0,0,0.15)', maxHeight: '240px', display: 'flex', flexDirection: 'column'
                }}>
                  <input
                    autoFocus
                    type="text"
                    placeholder="Search or create..."
                    value={tagSearch}
                    onChange={(e) => { setTagSearch(e.target.value); setTagSelectedIndex(0); }}
                    onKeyDown={(e) => {
                      const safeTags = tags || [];
                      const safeTagIds = task.tagIds || [];
                      const filteredTags = safeTags.filter(t => 
                        t.name.toLowerCase().includes(tagSearch.toLowerCase()) && 
                        !safeTagIds.includes(t.id)
                      );
                      if (e.key === 'ArrowUp') {
                        e.preventDefault();
                        setTagSelectedIndex(prev => Math.max(0, prev - 1));
                      } else if (e.key === 'ArrowDown') {
                        e.preventDefault();
                        const maxIdx = tagSearch.trim() && !safeTags.find(t => t.name.toLowerCase() === tagSearch.toLowerCase().trim()) ? filteredTags.length : Math.max(0, filteredTags.length - 1);
                        setTagSelectedIndex(prev => Math.min(maxIdx, prev + 1));
                      } else if (e.key === 'Enter') {
                        if (e.nativeEvent.isComposing) return;
                        e.preventDefault();
                        const safeTagIds2 = task.tagIds || [];
                        if (filteredTags.length === 0 && !tagSearch.trim()) {
                          setShowTagDropdown(false);
                          return;
                        }
                        if (tagSelectedIndex < filteredTags.length) {
                          const existing = filteredTags[tagSelectedIndex];
                          if (!safeTagIds2.includes(existing.id)) {
                            updateTask(taskId, { tagIds: [...safeTagIds2, existing.id] });
                          }
                        } else if (tagSearch.trim()) {
                          const colors = ['#888888', '#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                          const color = colors[Math.floor(Math.random() * colors.length)];
                          const newId = crypto.randomUUID();
                          addTag(tagSearch.trim(), color, newId);
                          updateTask(taskId, { tagIds: [...safeTagIds2, newId] });
                        }
                        setShowTagDropdown(false);
                        setTagSearch('');
                        setTagSelectedIndex(0);
                      } else if (e.key === 'Escape') {
                        setShowTagDropdown(false);
                      }
                    }}
                    style={{
                      width: '100%', padding: '6px 8px', border: 'none',
                      borderBottom: '1px solid var(--border-color)',
                      background: 'transparent', color: 'var(--text-primary)', outline: 'none',
                      fontSize: '0.85rem', boxSizing: 'border-box'
                    }}
                  />
                  <div style={{ overflowY: 'auto', flex: 1 }}>
                    {(() => {
                      const safeTags = tags || [];
                      const safeTagIds = task.tagIds || [];
                      const filteredTags = safeTags.filter(t => 
                        t.name.toLowerCase().includes(tagSearch.toLowerCase()) && 
                        !safeTagIds.includes(t.id)
                      );
                      return (
                        <>
                          {filteredTags.map((t, idx) => (
                            <div
                              key={t.id}
                              style={{
                                padding: '6px 8px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.85rem',
                                backgroundColor: tagSelectedIndex === idx ? 'var(--bg-hover)' : 'transparent', borderRadius: '4px'
                              }}
                              onClick={() => {
                                handleBatchUpdate({ tagIds: [...safeTagIds, t.id] });
                                setShowTagDropdown(false);
                                setTagSearch('');
                              }}
                              onMouseEnter={() => setTagSelectedIndex(idx)}
                            >
                              <span style={{ backgroundColor: t.color, width: '8px', height: '8px', borderRadius: '50%', flexShrink: 0 }}></span>
                              {t.name}
                            </div>
                          ))}
                          {tagSearch.trim() && !safeTags.find(t => t.name.toLowerCase() === tagSearch.toLowerCase().trim()) && (
                            <div
                              style={{
                                padding: '6px 8px', cursor: 'pointer', fontSize: '0.85rem', color: 'var(--brand-solid)',
                                borderTop: filteredTags.length > 0 ? '1px solid var(--border-color)' : 'none',
                                backgroundColor: tagSelectedIndex === filteredTags.length ? 'var(--bg-hover)' : 'transparent', borderRadius: '4px'
                              }}
                              onClick={() => {
                                const colors = ['#888888', '#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                                const color = colors[Math.floor(Math.random() * colors.length)];
                                const newId = crypto.randomUUID();
                                addTag(tagSearch.trim(), color, newId);
                                handleBatchUpdate({ tagIds: [...safeTagIds, newId] });
                                setShowTagDropdown(false);
                                setTagSearch('');
                              }}
                              onMouseEnter={() => setTagSelectedIndex(filteredTags.length)}
                            >
                              + "{tagSearch.trim()}" を新規作成
                            </div>
                          )}
                        </>
                      );
                    })()}
                  </div>
                </div>
              )}
            </div>
          </div>

          <div className="field-group">
            <label>Priority</label>
            <div className="field-value">
              <select 
                value={task.priority} 
                onChange={(e) => handleBatchUpdate({ priority: e.target.value as Priority })}
                style={{
                  backgroundColor: task.priority === 'none' ? 'transparent' : `var(--priority-${task.priority})`,
                  color: task.priority === 'none' ? 'var(--text-primary)' : 'white',
                  fontWeight: 600,
                  borderRadius: '4px',
                  padding: '4px 8px',
                  border: task.priority === 'none' ? '1px dashed var(--border-color)' : 'none'
                }}
              >
                <option value="none" style={{ color: 'var(--text-primary)', backgroundColor: 'var(--bg-surface)' }}>None</option>
                <option value="1st" style={{ color: 'white', backgroundColor: 'var(--priority-1st)' }}>1st</option>
                <option value="high" style={{ color: 'white', backgroundColor: 'var(--priority-high)' }}>High</option>
                <option value="mid" style={{ color: 'white', backgroundColor: 'var(--priority-mid)' }}>Mid</option>
                <option value="low" style={{ color: 'white', backgroundColor: 'var(--priority-low)' }}>Low</option>
              </select>
            </div>
          </div>

          <div className="field-group">
            <label>Estimated Time (m)</label>
            <div className="field-value">
              <input 
                type="number" 
                min="0"
                value={task.estimatedMinutes === 0 ? '' : task.estimatedMinutes} 
                onChange={(e) => {
                  const val = parseInt(e.target.value, 10);
                  handleBatchUpdate({ estimatedMinutes: isNaN(val) ? 0 : val });
                }}
                placeholder="0"
                style={{
                  width: '80px',
                  padding: '6px 10px',
                  borderRadius: '4px',
                  border: '1px solid var(--border-color)',
                  background: 'var(--bg-app)',
                  color: 'var(--text-primary)'
                }}
              />
            </div>
          </div>

          <div className="field-group">
            <label>Due Date</label>
            <div className="field-value" ref={dateInputRef} style={{ position: 'relative' }}>
              <span 
                onClick={() => { setShowDateInput(!showDateInput); setDateText(''); }}
                style={{ 
                  cursor: 'pointer', padding: '6px 10px', borderRadius: '4px', border: '1px solid var(--border-color)',
                  display: 'inline-block', minWidth: '140px', background: 'var(--bg-app)',
                  color: task.dueDate ? 'var(--text-primary)' : 'var(--text-secondary)'
                }}
              >
                {task.dueDate ? formatDateDisplay(task.dueDate) : '📅 Set Date'}
              </span>
              {showDateInput && (
                <div className="date-picker-dropdown" style={{
                  position: 'absolute', top: '100%', left: 0, zIndex: 20,
                  backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-color)',
                  borderRadius: '8px', padding: '12px', marginTop: '4px', minWidth: '260px',
                  boxShadow: '0 4px 16px rgba(0,0,0,0.18)'
                }}>
                  {/* Text input for natural language */}
                  <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '8px' }}>
                    <span style={{ fontSize: '0.85rem', color: 'var(--text-secondary)', flexShrink: 0 }}>📅</span>
                    <input
                      autoFocus
                      type="text"
                      placeholder="today, 明日, monday, 3/25..."
                      value={dateText}
                      onChange={(e) => setDateText(e.target.value)}
                      onKeyDown={(e) => {
                        if (e.key === 'Enter') {
                          e.preventDefault();
                          const lower = dateText.toLowerCase().trim();
                          if (lower === 'clear' || lower === 'クリア') {
                            handleBatchUpdate({ dueDate: null });
                            setShowDateInput(false);
                            setDateText('');
                            return;
                          }
                          const parsed = parseDateText(dateText);
                          if (parsed) {
                            handleBatchUpdate({ dueDate: parsed });
                            setShowDateInput(false);
                            setDateText('');
                          }
                        }
                        if (e.key === 'Escape') {
                          setShowDateInput(false);
                        }
                      }}
                      style={{
                        flex: 1, padding: '6px 8px', border: '1px solid var(--border-color)',
                        borderRadius: '6px', background: 'var(--bg-app)', color: 'var(--text-primary)',
                        fontSize: '0.85rem', outline: 'none', boxSizing: 'border-box'
                      }}
                    />
                    {task.dueDate && (
                      <button
                        onClick={() => {
                          handleBatchUpdate({ dueDate: null });
                          setShowDateInput(false);
                        }}
                        style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)', fontSize: '0.75rem', padding: '4px', flexShrink: 0 }}
                        title="クリア"
                      >✕</button>
                    )}
                  </div>
                  {/* Calendar */}
                  <DatePickerCalendar
                    value={task.dueDate ? task.dueDate.split('T')[0] : null}
                    onChange={(dateStr) => {
                      handleBatchUpdate({ dueDate: dateStr });
                      setShowDateInput(false);
                    }}
                    onClear={() => {
                      handleBatchUpdate({ dueDate: null });
                      setShowDateInput(false);
                    }}
                  />
                </div>
              )}
            </div>
          </div>

          <div className="field-group recurrence-field">
            <label>Recurrence</label>
            <div className="field-value">
              <select 
                value={task.recurrence?.frequency || 'none'} 
                onChange={(e) => handleToggleRecurrence(e.target.value as any)}
              >
                <option value="none">None</option>
                <option value="daily">Daily</option>
                <option value="weekly">Weekly</option>
                <option value="monthly">Monthly</option>
                <option value="yearly">Yearly</option>
              </select>

              {task.recurrence && (
                <div className="recurrence-custom-options">
                  <div className="interval-setting">
                    Every <input 
                      type="number" 
                      min="1" 
                      value={task.recurrence.interval} 
                      onChange={(e) => setSpecificRecurrence({ interval: parseInt(e.target.value) || 1 })}
                    /> {task.recurrence.frequency}(s)
                  </div>

                  {(task.recurrence.frequency === 'daily' || task.recurrence.frequency === 'weekly') && (
                    <div className="day-selector">
                      {DAYS.map((name, index) => (
                        <button
                          key={name}
                          className={`day-btn ${task.recurrence?.daysOfWeek?.includes(index) ? 'active' : ''}`}
                          onClick={() => toggleDayOfWeek(index)}
                        >
                          {name}
                        </button>
                      ))}
                    </div>
                  )}

                  {task.recurrence.frequency === 'monthly' && (
                    <div className="monthly-specifics">
                      <div className="monthly-option">
                        <input 
                          type="radio" 
                          id="monthly-day"
                          name="monthly-type" 
                          checked={!!task.recurrence.dayOfMonth} 
                          onChange={() => setSpecificRecurrence({ dayOfMonth: 1, weekOfMonth: undefined, daysOfWeek: undefined })}
                        />
                        <label htmlFor="monthly-day">On day</label>
                        <input 
                          type="number" 
                          min="1" max="31" 
                          value={task.recurrence.dayOfMonth || 1} 
                          onChange={(e) => setSpecificRecurrence({ dayOfMonth: parseInt(e.target.value) || 1 })}
                          disabled={!task.recurrence.dayOfMonth}
                        />
                      </div>
                      <div className="monthly-option">
                        <input 
                          type="radio" 
                          id="monthly-week"
                          name="monthly-type" 
                          checked={!!task.recurrence.weekOfMonth} 
                          onChange={() => setSpecificRecurrence({ dayOfMonth: undefined, weekOfMonth: 1, daysOfWeek: [1] })}
                        />
                        <label htmlFor="monthly-week">On the</label>
                        <select 
                          value={task.recurrence.weekOfMonth || 1} 
                          onChange={(e) => setSpecificRecurrence({ weekOfMonth: parseInt(e.target.value) })}
                          disabled={!task.recurrence.weekOfMonth}
                        >
                          <option value="1">1st</option>
                          <option value="2">2nd</option>
                          <option value="3">3rd</option>
                          <option value="4">4th</option>
                          <option value="-1">Last</option>
                        </select>
                        <select 
                          value={task.recurrence.daysOfWeek?.[0] || 1} 
                          onChange={(e) => setSpecificRecurrence({ daysOfWeek: [parseInt(e.target.value)] })}
                          disabled={!task.recurrence.weekOfMonth}
                        >
                          <option value="0">Sunday</option>
                          <option value="1">Monday</option>
                          <option value="2">Tuesday</option>
                          <option value="3">Wednesday</option>
                          <option value="4">Thursday</option>
                          <option value="5">Friday</option>
                          <option value="6">Saturday</option>
                        </select>
                      </div>
                    </div>
                  )}
                </div>
              )}
            </div>
          </div>
        </div>

        {/* Time Blocks Section */}
        <TimeBlocksSection task={task} taskId={taskId} addTimeBlock={addTimeBlock} updateTimeBlock={updateTimeBlock} deleteTimeBlock={deleteTimeBlock} />

        <div className="detail-section">
          <h3>Description</h3>
          <textarea 
            className="detail-description-area"
            value={task.description}
            onChange={handleUpdateDescription}
            placeholder="Add more detail to this task..."
          />
        </div>

        <div className="detail-section">
          <h3>Subtasks ({task.subtasks.filter(st => st.completed).length}/{task.subtasks.length})</h3>
          <div className="subtask-list">
            {task.subtasks.map(st => (
              <SubtaskItem
                key={st.id}
                subtask={st}
                taskId={taskId}
                toggleSubtask={toggleSubtask}
                updateSubtask={updateSubtask}
                deleteSubtask={deleteSubtask}
              />
            ))}
            <form onSubmit={handleAddSubtask} className="add-subtask-form">
              <input 
                value={newSubtask}
                onChange={(e) => setNewSubtask(e.target.value)}
                placeholder="Add subtask..."
              />
            </form>
          </div>
        </div>

        <div className="detail-section">
          <h3>Comments</h3>
          <div className="comment-list">
            {task.comments.map(c => (
              <div key={c.id} className="comment-item">
                <div className="comment-meta">
                  <span className="comment-user">{c.userName}</span>
                  <span className="comment-date">{new Date(c.createdAt).toLocaleString()}</span>
                  <div style={{ marginLeft: 'auto', display: 'flex', gap: '4px' }}>
                    <button
                      onClick={() => {
                        setEditingCommentId(c.id);
                        setEditCommentText(c.text);
                      }}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)', fontSize: '0.75rem', padding: '2px 6px' }}
                      title="Edit comment"
                    >
                      ✏️
                    </button>
                    <button
                      onClick={() => {
                        if (window.confirm('このコメントを削除しますか？')) {
                          deleteComment(taskId, c.id);
                        }
                      }}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--priority-high)', fontSize: '0.75rem', padding: '2px 6px' }}
                      title="Delete comment"
                    >
                      🗑️
                    </button>
                  </div>
                </div>
                {editingCommentId === c.id ? (
                  <div style={{ marginTop: '4px' }}>
                    <textarea
                      autoFocus
                      value={editCommentText}
                      onChange={(e) => setEditCommentText(e.target.value)}
                      style={{
                        width: '100%', minHeight: '60px', padding: '8px',
                        border: '1px solid var(--border-color)', borderRadius: '4px',
                        background: 'var(--bg-app)', color: 'var(--text-primary)',
                        fontSize: '0.85rem', resize: 'vertical', boxSizing: 'border-box'
                      }}
                    />
                    <div style={{ display: 'flex', gap: '6px', marginTop: '4px' }}>
                      <button
                        onClick={() => {
                          if (editCommentText.trim()) {
                            updateComment(taskId, c.id, editCommentText.trim());
                          }
                          setEditingCommentId(null);
                        }}
                        style={{
                          padding: '4px 12px', borderRadius: '4px', border: 'none',
                          background: 'var(--brand-solid)', color: 'white', cursor: 'pointer', fontSize: '0.8rem'
                        }}
                      >
                        Save
                      </button>
                      <button
                        onClick={() => setEditingCommentId(null)}
                        style={{
                          padding: '4px 12px', borderRadius: '4px', border: '1px solid var(--border-color)',
                          background: 'transparent', color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.8rem'
                        }}
                      >
                        Cancel
                      </button>
                    </div>
                  </div>
                ) : (
                  <div className="comment-text">{c.text}</div>
                )}
              </div>
            ))}
          </div>
          <form onSubmit={handleAddComment} className="add-comment-form">
            <textarea 
              value={newComment}
              onChange={(e) => setNewComment(e.target.value)}
              placeholder="Ask a question or post an update..."
            />
            <button type="submit" disabled={!newComment.trim()}>Comment</button>
          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import type { Task, Priority } from '../types';
import { useTaskStore } from '../store/useTaskStore';
import type { ColumnId } from '../store/useTaskStore';
import { useSortable } from '@dnd-kit/sortable';
import { CSS } from '@dnd-kit/utilities';
import { parseDateText, formatDateDisplay } from '../utils/dateParser';
import { DatePickerCalendar } from './DatePickerCalendar';
import { sortProjectsCustom } from '../utils/sortUtils';
import './TaskItem.css';

interface Props {
  task: Task;
}

export const TaskItem: React.FC<Props> = ({ task }) => {
  const { 
    projects,
    tags,
    moveTask,
    updateTask,
    addProject,
    addTag,
    toggleTaskCompletion, 
    setActiveProject,
    activeTimerTaskId,
    startTimer,
    pauseTimer,
    columnOrder,
    columnWidths,
    setSelectedTaskId,
    selectedTaskIds,
    toggleTaskSelection,
    clearSelection,
    updateBulkTasksDate,
    setDailyLog,
    highlightedTaskId,
    timerStartTimestamp,
    timerTick,
    deleteTask
  } = useTaskStore();
  const [showProjectDropdown, setShowProjectDropdown] = useState(false);
  const [projectSearch, setProjectSearch] = useState('');
  const [projectSelectedIndex, setProjectSelectedIndex] = useState(0);

  const rowRef = useRef<HTMLDivElement>(null);

  // Auto-scroll when highlighted
  useEffect(() => {
    if (highlightedTaskId === task.id && rowRef.current) {
      rowRef.current.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [highlightedTaskId, task.id]);

  const [showTagDropdown, setShowTagDropdown] = useState(false);
  const [tagSearch, setTagSearch] = useState('');
  const [tagSelectedIndex, setTagSelectedIndex] = useState(0);
  const [isEditingTime, setIsEditingTime] = useState(false);
  const [editMinutes, setEditMinutes] = useState<string>('0');
  const [isEditingTitle, setIsEditingTitle] = useState(false);
  const [editTitleValue, setEditTitleValue] = useState(task.title);

  const [showDateInput, setShowDateInput] = useState(false);
  const [dateText, setDateText] = useState('');
  const dateInputRef = useRef<HTMLDivElement>(null);

  const handleBatchUpdate = (updates: Partial<Task>) => {
    if (selectedTaskIds.length > 1 && selectedTaskIds.includes(task.id)) {
      selectedTaskIds.forEach(id => updateTask(id, updates));
    } else {
      updateTask(task.id, updates);
    }
  };

  const handleProjectUpdate = (newProjectId: string | null) => {
    if (selectedTaskIds.length > 1 && selectedTaskIds.includes(task.id)) {
      selectedTaskIds.forEach(id => moveTask(id, newProjectId));
    } else {
      moveTask(task.id, newProjectId);
    }
  };

  const getLocalDateStr = (d: Date = new Date()) => {
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${y}-${m}-${day}`;
  };

  const todayStr = getLocalDateStr();
  const isTimerActive = activeTimerTaskId === task.id;

  const liveDelta = (isTimerActive && timerStartTimestamp) 
    ? Math.floor((timerTick - timerStartTimestamp) / 1000) 
    : 0;
  const todayTimeSecs = (task.dailyLogs?.[todayStr] || 0) + liveDelta;
  const totalDisplayTime = task.accumulatedTime + liveDelta;

  const project = projects.find(p => p.id === task.projectId);
  const projectDropdownRef = useRef<HTMLDivElement>(null);
  const tagDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (projectDropdownRef.current && !projectDropdownRef.current.contains(event.target as Node)) {
        setShowProjectDropdown(false);
      }
      if (tagDropdownRef.current && !tagDropdownRef.current.contains(event.target as Node)) {
        setShowTagDropdown(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);

    const handleClickOutsideDate = (event: MouseEvent) => {
      if (dateInputRef.current && !dateInputRef.current.contains(event.target as Node)) {
        setShowDateInput(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutsideDate);

    return () => {
      document.removeEventListener('mousedown', handleClickOutside);
      document.removeEventListener('mousedown', handleClickOutsideDate);
    };
  }, []);

  const handleTimerClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isTimerActive) {
      pauseTimer();
    } else {
      startTimer(task.id);
    }
  };

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    if (h > 0) return `${h}h ${m}m ${s}s`;
    if (m > 0) return `${m}m ${s}s`;
    return `${s}s`;
  };

  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: task.id });

  const isMultiSelected = selectedTaskIds.includes(task.id);

  const rowStyle = {
    transform: CSS.Transform.toString(transform),
    transition,
    opacity: isDragging ? 0.4 : 1,
    position: isDragging ? 'relative' : 'static',
    zIndex: isDragging ? 1 : 0,
  } as React.CSSProperties;

  // Build className-based selection/timer styles for the task-row
  const rowClasses = ['task-row'];
  if (isTimerActive) rowClasses.push('timer-active');
  if (isMultiSelected) rowClasses.push('multi-selected');
  if (task.completed) rowClasses.push('completed');
  if (highlightedTaskId === task.id) rowClasses.push('search-highlighted');

  const getPriorityColor = (p: Priority) => {
    if (p === '1st') return 'var(--priority-1st)';
    if (p === 'high') return 'var(--priority-high)';
    if (p === 'mid') return 'var(--priority-mid)';
    if (p === 'low') return 'var(--priority-low)';
    return 'transparent'; // 'none'
  };


  const handleDateUpdate = (newDate: string | null) => {
    if (selectedTaskIds.length > 1 && selectedTaskIds.includes(task.id)) {
      updateBulkTasksDate(selectedTaskIds, newDate);
    } else {
      updateTask(task.id, { dueDate: newDate });
    }
  };

  const filteredProjects = projects.filter(p => 
    p.id !== 'p1' && p.name.toLowerCase().includes(projectSearch.toLowerCase())
  ).sort((a, b) => sortProjectsCustom(a.name, b.name));

  const handleRowClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (e.ctrlKey || e.metaKey) {
      e.preventDefault();
      toggleTaskSelection(task.id, true);
    } else {
      clearSelection();
      toggleTaskSelection(task.id, false);
    }
  };

  const renderCell = (colId: ColumnId) => {
    switch (colId) {
      case 'name':
        return (
          <div key="name" className="task-cell cell-name" tabIndex={0}
            style={{ width: `${columnWidths.name}px`, minWidth: `${columnWidths.name}px`, maxWidth: `${columnWidths.name}px`, flexShrink: 0, flexGrow: 0 }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                setSelectedTaskId(task.id);
              }
            }}
          >
            <button 
              className="complete-btn" 
              onClick={(e) => {
                e.stopPropagation();
                // Confirm if there are incomplete subtasks
                const incompleteSubtasks = task.subtasks.filter(st => !st.completed);
                if (incompleteSubtasks.length > 0) {
                  if (!window.confirm(`サブタスクが${incompleteSubtasks.length}件残っていますが、完了してよいですか？`)) {
                    return;
                  }
                }
                toggleTaskCompletion(task.id);
              }}
              title="Mark Complete"
            >
              <div className="check-circle" />
            </button>
            {isEditingTitle ? (
              <input
                className="task-title-input"
                autoFocus
                value={editTitleValue}
                onChange={(e) => setEditTitleValue(e.target.value)}
                onBlur={() => {
                  if (editTitleValue.trim() && editTitleValue !== task.title) {
                    updateTask(task.id, { title: editTitleValue.trim() });
                  } else {
                    setEditTitleValue(task.title);
                  }
                  setIsEditingTitle(false);
                }}
                onKeyDown={(e) => {
                  if (e.key === 'ArrowLeft' || e.key === 'ArrowRight') {
                    e.stopPropagation();
                  }
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    (e.target as HTMLInputElement).blur();
                  }
                  if (e.key === 'Escape') {
                    setEditTitleValue(task.title);
                    setIsEditingTitle(false);
                  }
                }}
                onClick={(e) => e.stopPropagation()}
                style={{ flex: 1, border: 'none', background: 'transparent', outline: 'none', color: 'var(--text-primary)', fontSize: 'inherit', fontFamily: 'inherit', padding: '2px 4px', borderBottom: '2px solid var(--brand-solid)' }}
              />
            ) : (
              <div style={{ flex: 1, display: 'flex', minWidth: 0, alignItems: 'center' }}>
                <span 
                  onClick={(e) => {
                    e.stopPropagation();
                    setEditTitleValue(task.title);
                    setIsEditingTitle(true);
                  }}
                  style={{ 
                    cursor: 'text', 
                    whiteSpace: 'nowrap', 
                    overflow: 'hidden', 
                    textOverflow: 'ellipsis', 
                    maxWidth: '100%' 
                  }}
                  title={task.title}
                >
                  {isTimerActive && <span className="timer-indicator" style={{ marginRight: '4px' }}>⏱️ </span>}
                  {task.title}
                </span>
              </div>
            )}
            <button
              className="icon-btn delete-btn"
              onClick={(e) => {
                e.stopPropagation();
                if (window.confirm('このタスクを削除しますか？')) {
                  deleteTask(task.id);
                }
              }}
              title="Delete Task"
              style={{ padding: '2px 6px', fontSize: '0.75rem', flexShrink: 0, display: 'none', alignItems: 'center', opacity: 0.5, color: 'var(--priority-high)' }}
            >
              🗑️
            </button>
            {task.subtasks.length > 0 && (
              <span
                className="subtask-badge"
                title={`サブタスク: ${task.subtasks.filter(st => st.completed).length}/${task.subtasks.length} 完了`}
                style={{
                  fontSize: '0.7rem',
                  padding: '1px 5px',
                  borderRadius: '8px',
                  backgroundColor: task.subtasks.every(st => st.completed) ? 'rgba(37, 194, 109, 0.2)' : 'rgba(110, 68, 225, 0.15)',
                  color: task.subtasks.every(st => st.completed) ? 'var(--priority-low)' : 'var(--brand-solid)',
                  fontWeight: 600,
                  flexShrink: 0,
                  display: 'flex',
                  alignItems: 'center',
                  gap: '2px'
                }}
              >
                📋{task.subtasks.filter(st => !st.completed).length > 0 ? task.subtasks.filter(st => !st.completed).length : '✓'}
              </span>
            )}
            <button
              className="icon-btn details-btn"
              onClick={(e) => {
                e.stopPropagation();
                setSelectedTaskId(task.id);
              }}
              title="Open Details"
              style={{ padding: '2px 6px', fontSize: '0.75rem', flexShrink: 0, display: 'flex', alignItems: 'center', opacity: 0.5 }}
            >
              詳細 〉
            </button>
          </div>
        );
      case 'time': {
        const displayLabel = totalDisplayTime > 0 || isTimerActive 
            ? `${formatTime(todayTimeSecs)} (${formatTime(totalDisplayTime)})`
            : '';
        return (
          <div key="time" className="task-cell cell-time" tabIndex={0}
            style={{ width: `${columnWidths.time}px`, minWidth: `${columnWidths.time}px`, maxWidth: `${columnWidths.time}px`, flexShrink: 0, flexGrow: 0 }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                setEditMinutes(Math.floor(todayTimeSecs / 60).toString());
                setIsEditingTime(true);
              }
            }}
          >
            {isEditingTime ? (
              <input 
                type="number"
                value={editMinutes}
                onChange={e => setEditMinutes(e.target.value)}
                onBlur={() => {
                  if (isEditingTime) {
                    const val = parseInt(editMinutes, 10);
                    if (!isNaN(val) && val >= 0) {
                      setDailyLog(task.id, todayStr, val * 60);
                    }
                    setIsEditingTime(false);
                  }
                }}
                onKeyDown={(e) => {
                  if (e.key === 'Enter') {
                    e.preventDefault();
                    if (e.nativeEvent.isComposing) return;
                    e.stopPropagation();

                    const val = parseInt(editMinutes, 10);
                    if (!isNaN(val) && val >= 0) {
                      setDailyLog(task.id, todayStr, val * 60);
                    }
                    setIsEditingTime(false);
                  }
                  if (e.key === 'Escape') {
                    setIsEditingTime(false);
                  }
                }}
                autoFocus
                onFocus={e => e.target.select()}
                style={{ width: '60px', padding: '2px 4px', fontSize: '0.75rem', outline: 'none', border: '1px solid var(--brand-solid)', borderRadius: '4px', background: 'var(--bg-app)', color: 'var(--text-primary)' }}
                min="0"
                step="1"
                title="Enter minutes"
              />
            ) : (
              <span 
                className={`timer-display ${isTimerActive ? 'brand-text' : ''}`} 
                onClick={(e) => {
                  e.stopPropagation();
                  setEditMinutes(Math.floor(todayTimeSecs / 60).toString());
                  setIsEditingTime(true);
                }}
                title="Click to edit today's minutes"
                style={{ fontSize: '0.75rem', fontWeight: 600, color: 'var(--text-secondary)', cursor: 'pointer', display: 'inline-block', minWidth: '40px', padding: '2px 0' }}
              >
                 {displayLabel || <span style={{ opacity: 0.5 }}>0m (0m)</span>}
              </span>
            )}
            <div className="task-actions" style={{ opacity: isTimerActive ? 1 : undefined }}>
              <button 
                className={`icon-btn timer-btn ${isTimerActive ? 'active brand-text' : ''}`} 
                onClick={handleTimerClick}
                title={isTimerActive ? "Pause Timer" : "Start Timer"}
              >
                {isTimerActive ? '⏸' : '▶'}
              </button>
            </div>
          </div>
        );
      }
      case 'project': {
        return (
          <div key="project" className="task-cell cell-project" tabIndex={0}
            style={{ width: `${columnWidths.project}px`, minWidth: `${columnWidths.project}px`, maxWidth: `${columnWidths.project}px`, flexShrink: 0, flexGrow: 0, position: 'relative', overflow: 'visible' }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                e.stopPropagation();
                setShowProjectDropdown(!showProjectDropdown);
                setProjectSearch('');
              }
            }}
          >
             <div className="project-selector-wrapper" ref={projectDropdownRef} style={{ display: 'flex', alignItems: 'center', gap: '4px', width: '100%' }}>
               <span 
                 className="pill project-pill"
                 style={{ cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', flex: 1, overflow: 'hidden' }}
                 onClick={(e) => {
                   e.stopPropagation();
                   if (project) {
                     setActiveProject(project.id);
                   } else {
                     setShowProjectDropdown(!showProjectDropdown);
                     setProjectSearch('');
                   }
                 }}
                 title={project ? `${project.name} のタスク一覧を表示` : 'プロジェクトを選択'}
               >
                 {project ? (
                   <>
                     <span className="color-dot" style={{ backgroundColor: project.color, width: '8px', height: '8px', borderRadius: '50%' }}></span>
                     <span style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>{project.name}</span>
                   </>
                 ) : 'Select Project'}
               </span>
               <button
                 className="project-change-btn"
                 style={{ background: 'none', border: 'none', color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.75rem', padding: '2px 4px', flexShrink: 0, borderRadius: '3px' }}
                 onClick={(e) => {
                   e.stopPropagation();
                   setShowProjectDropdown(!showProjectDropdown);
                   setProjectSearch('');
                 }}
                 title="プロジェクトを変更"
               >
                 ›
               </button>
               {showProjectDropdown && (
                 <div className="project-dropdown" style={{
                   position: 'absolute', top: '100%', left: 0, zIndex: 10,
                   backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-color)',
                   borderRadius: '6px', padding: '4px', marginTop: '4px', minWidth: '180px',
                   boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                   maxHeight: '240px', display: 'flex', flexDirection: 'column'
                 }}>
                   <input
                     autoFocus
                     type="text"
                     placeholder="Search or create..."
                     value={projectSearch}
                     onChange={(e) => {
                       setProjectSearch(e.target.value);
                       setProjectSelectedIndex(0);
                     }}
                     onClick={(e) => e.stopPropagation()}
                     onKeyDown={(e) => {
                       if (e.key === 'ArrowUp') {
                         e.preventDefault(); e.stopPropagation();
                         setProjectSelectedIndex(prev => Math.max(0, prev - 1));
                       } else if (e.key === 'ArrowDown') {
                         e.preventDefault(); e.stopPropagation();
                         const maxIdx = projectSearch.trim() && !projects.find(p => p.name.toLowerCase() === projectSearch.toLowerCase().trim()) ? filteredProjects.length + 1 : Math.max(0, filteredProjects.length);
                         setProjectSelectedIndex(prev => Math.min(maxIdx, prev + 1));
                       } else if (e.key === 'Enter') {
                         if (e.nativeEvent.isComposing) return;
                         e.preventDefault(); e.stopPropagation();
                         if (projectSelectedIndex === 0) {
                           handleProjectUpdate(null);
                         } else if (projectSelectedIndex - 1 < filteredProjects.length) {
                           handleProjectUpdate(filteredProjects[projectSelectedIndex - 1].id);
                         } else if (projectSearch.trim()) {
                           const colors = ['#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                           const color = colors[Math.floor(Math.random() * colors.length)];
                           const newId = crypto.randomUUID();
                           addProject(projectSearch.trim(), color, newId);
                           handleProjectUpdate(newId);
                         }
                         setShowProjectDropdown(false);
                         setProjectSearch('');
                         setProjectSelectedIndex(0);
                       }
                     }}
                     style={{
                       width: '100%', padding: '6px 8px', border: 'none',
                       borderBottom: '1px solid var(--border-color)',
                       background: 'transparent', color: 'var(--text-primary)',
                       fontSize: '0.8rem', outline: 'none', boxSizing: 'border-box'
                     }}
                   />
                   <div style={{ overflowY: 'auto', flex: 1 }}>
                     <div 
                       className="project-dropdown-item"
                       style={{ 
                         padding: '6px 12px', fontSize: '0.875rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', borderRadius: '4px',
                         backgroundColor: projectSelectedIndex === 0 ? 'var(--bg-hover)' : 'transparent'
                       }}
                       onClick={(e) => { 
                         e.stopPropagation(); 
                         handleProjectUpdate(null); 
                         setShowProjectDropdown(false); 
                         setProjectSearch(''); 
                       }}
                       onMouseEnter={() => setProjectSelectedIndex(0)}
                     >
                       <span className="color-dot" style={{ backgroundColor: 'transparent', border: '1px dashed var(--border-color)', width: '8px', height: '8px', borderRadius: '50%' }}></span>
                       No Project
                     </div>
                     {filteredProjects.map((p, idx) => (
                       <div 
                         key={p.id} className="project-dropdown-item"
                         style={{ 
                           padding: '6px 12px', fontSize: '0.875rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px', borderRadius: '4px',
                           backgroundColor: projectSelectedIndex === idx + 1 ? 'var(--bg-hover)' : 'transparent'
                         }}
                         onClick={(e) => { 
                           e.stopPropagation(); 
                           handleProjectUpdate(p.id); 
                           setShowProjectDropdown(false); 
                           setProjectSearch(''); 
                         }}
                         onMouseEnter={() => setProjectSelectedIndex(idx + 1)}
                       >
                         <span className="color-dot" style={{ backgroundColor: p.color, width: '8px', height: '8px', borderRadius: '50%' }}></span>
                         {p.name}
                       </div>
                     ))}
                     {projectSearch.trim() && !projects.find(p => p.name.toLowerCase() === projectSearch.toLowerCase().trim()) && (
                       <div 
                         className="project-dropdown-item create-new"
                         style={{
                           padding: '6px 12px', fontSize: '0.875rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '8px',
                           borderRadius: '4px', borderTop: '1px solid var(--border-color)', marginTop: '4px', color: 'var(--brand-solid)', fontWeight: 500,
                           backgroundColor: projectSelectedIndex === filteredProjects.length + 1 ? 'var(--bg-hover)' : 'transparent'
                         }}
                         onClick={(e) => {
                           e.stopPropagation();
                           const colors = ['#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                           const color = colors[Math.floor(Math.random() * colors.length)];
                           const newId = crypto.randomUUID();
                           addProject(projectSearch.trim(), color, newId);
                           handleProjectUpdate(newId);
                           setShowProjectDropdown(false);
                           setProjectSearch('');
                         }}
                         onMouseEnter={() => setProjectSelectedIndex(filteredProjects.length + 1)}
                       >
                         + "{projectSearch.trim()}" を新規作成
                       </div>
                     )}
                   </div>
                 </div>
               )}
             </div>
          </div>
        );
      }
      case 'tags': {
        const safeTags = tags || [];
        const safeTagIds = task.tagIds || [];
        const taskTags = safeTagIds.map(id => safeTags.find(t => t.id === id)).filter(Boolean) as {id: string, name: string, color: string}[];
        const filteredTags = safeTags.filter(t => 
          t.name.toLowerCase().includes(tagSearch.toLowerCase()) && 
          !safeTagIds.includes(t.id)
        ).sort((a,b)=>sortProjectsCustom(a.name, b.name));

        return (
          <div key="tags" className="task-cell cell-tags" tabIndex={0}
            style={{ width: `${columnWidths.tags}px`, minWidth: `${columnWidths.tags}px`, maxWidth: `${columnWidths.tags}px`, flexShrink: 0, flexGrow: 0, position: 'relative', overflow: 'visible' }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                e.stopPropagation();
                setShowTagDropdown(!showTagDropdown);
                setTagSearch('');
              }
            }}
          >
            <div className="tag-selector-wrapper" ref={tagDropdownRef} style={{ display: 'flex', gap: '4px', flexWrap: 'wrap', alignItems: 'center', width: '100%' }}>
              {taskTags.map(tag => (
                <span 
                  key={tag.id} 
                  className="pill tag-pill" 
                  style={{ backgroundColor: tag.color + '33', color: tag.color, cursor: 'pointer' }}
                  onClick={(e) => {
                    e.stopPropagation();
                    setActiveProject(`t-${tag.id}`);
                  }}
                  title={`${tag.name} のタスク一覧を表示`}
                >
                  {tag.name}
                  <button
                    className="tag-delete-btn"
                    onClick={(e) => {
                      e.stopPropagation();
                      const newTagIds = safeTagIds.filter(id => id !== tag.id);
                      updateTask(task.id, { tagIds: newTagIds });
                    }}
                    title="タグを削除"
                  >
                    －
                  </button>
                </span>
              ))}
              <button 
                className="add-tag-btn"
                style={{ background: 'none', border: 'none', color: 'var(--text-secondary)', cursor: 'pointer', fontSize: '0.875rem', padding: '0 4px' }}
                onClick={(e) => {
                  e.stopPropagation();
                  setShowTagDropdown(!showTagDropdown);
                  setTagSearch('');
                }}
              >
                +
              </button>

              {showTagDropdown && (
                <div className="tag-dropdown" style={{
                  position: 'absolute', top: '100%', left: 0, zIndex: 10,
                  backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-color)',
                  borderRadius: '6px', padding: '4px', marginTop: '4px', minWidth: '180px',
                  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                  maxHeight: '240px', display: 'flex', flexDirection: 'column'
                }}>
                  <input
                    autoFocus
                    type="text"
                    placeholder="Search or create..."
                    value={tagSearch}
                    onChange={(e) => {
                      setTagSearch(e.target.value);
                      setTagSelectedIndex(0);
                    }}
                    onClick={(e) => e.stopPropagation()}
                    onKeyDown={(e) => {
                      if (e.key === 'ArrowUp') {
                        e.preventDefault(); e.stopPropagation();
                        setTagSelectedIndex(prev => Math.max(0, prev - 1));
                      } else if (e.key === 'ArrowDown') {
                        e.preventDefault(); e.stopPropagation();
                        const maxIdx = tagSearch.trim() && !safeTags.find(t => t.name.toLowerCase() === tagSearch.toLowerCase().trim()) ? filteredTags.length : Math.max(0, filteredTags.length - 1);
                        setTagSelectedIndex(prev => Math.min(maxIdx, prev + 1));
                      } else if (e.key === 'Enter') {
                        if (e.nativeEvent.isComposing) return;
                        e.preventDefault(); e.stopPropagation();
                        if (filteredTags.length === 0 && !tagSearch.trim()) {
                          setShowTagDropdown(false);
                          return;
                        }
                        if (tagSelectedIndex < filteredTags.length) {
                          const existing = filteredTags[tagSelectedIndex];
                          if (!safeTagIds.includes(existing.id)) {
                            handleBatchUpdate({ tagIds: [...safeTagIds, existing.id] });
                          }
                        } else if (tagSearch.trim()) {
                          const colors = ['#888888', '#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                          const color = colors[Math.floor(Math.random() * colors.length)];
                          const newId = crypto.randomUUID();
                          addTag(tagSearch.trim(), color, newId);
                          handleBatchUpdate({ tagIds: [...safeTagIds, newId] });
                        }
                        setShowTagDropdown(false);
                        setTagSearch('');
                        setTagSelectedIndex(0);
                      }
                    }}
                    style={{
                      width: '100%', padding: '6px 8px', border: 'none',
                      borderBottom: '1px solid var(--border-color)',
                      background: 'transparent', color: 'var(--text-primary)', outline: 'none'
                    }}
                  />
                  <div style={{ overflowY: 'auto', flex: 1 }}>
                    {filteredTags.map((t, idx) => (
                      <div 
                        key={t.id}
                        style={{ 
                          padding: '6px 8px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '6px', fontSize: '0.8125rem',
                          backgroundColor: tagSelectedIndex === idx ? 'var(--bg-hover)' : 'transparent'
                        }}
                        onClick={(e) => {
                          e.stopPropagation();
                          handleBatchUpdate({ tagIds: [...safeTagIds, t.id] });
                          setShowTagDropdown(false);
                          setTagSearch('');
                        }}
                        onMouseEnter={() => setTagSelectedIndex(idx)}
                      >
                        <span className="color-dot" style={{ backgroundColor: t.color, width: '8px', height: '8px', borderRadius: '50%' }}></span>
                        {t.name}
                      </div>
                    ))}
                    {tagSearch.trim() && !safeTags.find(t => t.name.toLowerCase() === tagSearch.toLowerCase().trim()) && (
                      <div
                        style={{ 
                          padding: '6px 8px', cursor: 'pointer', fontSize: '0.8125rem', color: 'var(--brand-solid)', borderTop: filteredTags.length > 0 ? '1px solid var(--border-color)' : 'none',
                          backgroundColor: tagSelectedIndex === filteredTags.length ? 'var(--bg-hover)' : 'transparent'
                        }}
                        onClick={(e) => {
                          e.stopPropagation();
                          const colors = ['#888888', '#F06A6A', '#25C26D', '#6A44E1', '#E89A2D', '#2D9CDB'];
                          const color = colors[Math.floor(Math.random() * colors.length)];
                          const newId = crypto.randomUUID();
                          addTag(tagSearch.trim(), color, newId);
                          handleBatchUpdate({ tagIds: [...safeTagIds, newId] });
                          setShowTagDropdown(false);
                          setTagSearch('');
                        }}
                        onMouseEnter={() => setTagSelectedIndex(filteredTags.length)}
                      >
                        + "{tagSearch.trim()}" を新規作成
                      </div>
                    )}
                  </div>
                </div>
              )}
            </div>
          </div>
        );
      }
      case 'priority':
        return (
          <div key="priority" className="task-cell cell-priority" tabIndex={0}
            style={{ width: `${columnWidths.priority}px`, minWidth: `${columnWidths.priority}px`, maxWidth: `${columnWidths.priority}px`, flexShrink: 0, flexGrow: 0 }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                const sel = e.currentTarget.querySelector('select') as HTMLSelectElement;
                if (sel) sel.focus();
              }
            }}
          >
            <select
              value={task.priority}
              onChange={(e) => handleBatchUpdate({ priority: e.target.value as any })}
              onClick={(e) => e.stopPropagation()}
              style={{
                backgroundColor: getPriorityColor(task.priority),
                color: task.priority === 'none' ? 'var(--text-secondary)' : 'white',
                border: task.priority === 'none' ? '1px dashed var(--border-color)' : 'none',
                borderRadius: '12px',
                padding: '2px 8px',
                fontSize: '0.75rem',
                fontWeight: 600,
                outline: 'none',
                cursor: 'pointer',
                appearance: 'none',
                textAlign: 'center'
              }}
            >
              <option value="none">—</option>
              <option value="1st">1st</option>
              <option value="high">High</option>
              <option value="mid">Mid</option>
              <option value="low">Low</option>
            </select>
          </div>
        );
      case 'date': {
        const displayDate = formatDateDisplay(task.dueDate);
        return (
          <div key="date" className="task-cell cell-date" ref={dateInputRef} tabIndex={0}
            style={{ width: `${columnWidths.date}px`, minWidth: `${columnWidths.date}px`, maxWidth: `${columnWidths.date}px`, flexShrink: 0, flexGrow: 0, position: 'relative' }}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                e.preventDefault();
                setShowDateInput(!showDateInput);
                setDateText('');
              }
            }}
          >
            <span 
              className="date-display-btn"
              onClick={(e) => { e.stopPropagation(); setShowDateInput(!showDateInput); setDateText(''); }}
              style={{ 
                cursor: 'pointer', fontSize: '0.85rem', color: task.dueDate ? 'var(--text-primary)' : 'var(--text-secondary)',
                padding: '2px 6px', borderRadius: '4px', display: 'inline-block',
                border: '1px solid transparent'
              }}
              onMouseEnter={(e) => e.currentTarget.style.borderColor = 'var(--border-color)'}
              onMouseLeave={(e) => e.currentTarget.style.borderColor = 'transparent'}
            >
              {displayDate || '📅 set'}
            </span>
            {showDateInput && (
              <div className="date-picker-dropdown" style={{
                position: 'absolute', top: '100%', left: 0, zIndex: 20,
                backgroundColor: 'var(--bg-surface)', border: '1px solid var(--border-color)',
                borderRadius: '8px', padding: '12px', marginTop: '4px', minWidth: '260px',
                boxShadow: '0 4px 16px rgba(0,0,0,0.18)'
              }} onClick={e => e.stopPropagation()}>
                {/* Text input for natural language */}
                <div style={{ display: 'flex', alignItems: 'center', gap: '6px', marginBottom: '8px' }}>
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)', flexShrink: 0 }}>📅</span>
                  <input
                    autoFocus
                    type="text"
                    placeholder="today, 明日, monday, 3/25..."
                    value={dateText}
                    onChange={(e) => setDateText(e.target.value)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter') {
                        e.preventDefault();
                        const lower = dateText.toLowerCase().trim();
                        if (lower === 'clear' || lower === 'クリア') {
                          handleDateUpdate(null);
                          setShowDateInput(false);
                          setDateText('');
                          return;
                        }
                        const parsed = parseDateText(dateText);
                        if (parsed) {
                          handleDateUpdate(parsed);
                          setShowDateInput(false);
                          setDateText('');
                        }
                      }
                      if (e.key === 'Escape') {
                        setShowDateInput(false);
                      }
                    }}
                    style={{
                      flex: 1, padding: '6px 8px', border: '1px solid var(--border-color)',
                      borderRadius: '6px', background: 'var(--bg-app)', color: 'var(--text-primary)',
                      fontSize: '0.8rem', outline: 'none', boxSizing: 'border-box'
                    }}
                  />
                  {task.dueDate && (
                    <button
                      onClick={() => {
                        handleDateUpdate(null);
                        setShowDateInput(false);
                      }}
                      style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--text-secondary)', fontSize: '0.75rem', padding: '4px', flexShrink: 0 }}
                      title="クリア"
                    >✕</button>
                  )}
                </div>
                {/* Calendar */}
                <DatePickerCalendar
                  value={task.dueDate ? task.dueDate.split('T')[0] : null}
                  onChange={(dateStr) => {
                    handleDateUpdate(dateStr);
                    setShowDateInput(false);
                  }}
                  onClear={() => {
                    handleDateUpdate(null);
                    setShowDateInput(false);
                  }}
                />
              </div>
            )}
          </div>
        );
      }
      case 'estimatedMinutes':
        return (
          <div key="estimatedMinutes" className="task-cell cell-estimatedMinutes" tabIndex={0}
            style={{ width: `${columnWidths.estimatedMinutes}px`, minWidth: `${columnWidths.estimatedMinutes}px`, maxWidth: `${columnWidths.estimatedMinutes}px`, flexShrink: 0, flexGrow: 0 }}
          >
            <input 
              type="number"
              className="estimated-minutes-input"
              value={task.estimatedMinutes === 0 ? '' : task.estimatedMinutes}
              onChange={e => {
                const val = parseInt(e.target.value, 10);
                updateTask(task.id, { estimatedMinutes: isNaN(val) ? 0 : val });
              }}
              placeholder="0"
              onClick={e => e.stopPropagation()}
              onKeyDown={(e) => {
                if (e.key === 'Enter') e.currentTarget.blur();
              }}
              style={{
                width: '60px',
                padding: '2px 4px',
                fontSize: '0.75rem',
                outline: 'none',
                border: '1px solid transparent',
                borderRadius: '4px',
                background: 'transparent',
                color: 'var(--text-primary)',
                textAlign: 'center'
              }}
              onMouseEnter={(e) => e.currentTarget.style.border = '1px solid var(--border-color)'}
              onMouseLeave={(e) => e.currentTarget.style.border = '1px solid transparent'}
              title="Estimate in minutes"
              min="0"
            />
          </div>
        );
      case 'createdAt':
        return (
          <div key="createdAt" className="task-cell cell-createdAt" tabIndex={0}
            style={{ width: `${columnWidths.createdAt}px`, minWidth: `${columnWidths.createdAt}px`, maxWidth: `${columnWidths.createdAt}px`, flexShrink: 0, flexGrow: 0 }}
          >
            <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>
              {task.createdAt ? new Date(task.createdAt).toLocaleDateString('ja-JP') : ''}
            </span>
          </div>
        );
      default:
        return null;
    }
  };

  return (
    <div 
      ref={(node) => {
        setNodeRef(node);
        // @ts-ignore
        rowRef.current = node;
      }} 
      style={rowStyle} 
      {...attributes} 
      {...listeners}
    >
      <div 
        className={rowClasses.join(' ')}
        onClick={handleRowClick}
      >
        {columnOrder.map(colId => renderCell(colId))}
      </div>
    </div>
  );
};

